\begin{align*}f(2) &= \frac 13 \\ f(3) &= \left(\frac 13\right)^2 \\ f(4) &= \left(\frac 13\right)^3 - \left(\frac 23\right)f(2) \\ f(5) &= \left(\frac 13\right)^4 - 2\left(\frac 13\right)f(3) \\ f(6) &= \left(\frac 13\right)^5 - 3\left(\frac 13\right)^2f(3) = \left(\frac 13\right)^5 - 2\left(\frac 23\right)^2 \\ f(7) &= \left(\frac 13\right)^6 - 4\left(\frac 13\right)^3f(3) = \left(\frac 13\right)^6 - 3\left(\frac 13\right)^2f(3) = \left(\frac 13\right)^6 - 2\left(\frac 23\right)^3 \equiv \frac 1{729} - \frac 8{729} = -\frac 7{729}.\end{align*}
